using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;

// ─── Configuration ───────────────────────────────────────────────────
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.ForegroundColor = ConsoleColor.Yellow;
    Console.WriteLine("Set the OPENAI_API_KEY environment variable to run this agent.");
    Console.WriteLine("Optionally set OPENAI_MODEL (default: gpt-4o-mini).");
    Console.ResetColor();
    return 1;
}

// ─── In-memory notes store ───────────────────────────────────────────
var notes = new List<ResearchNote>();

// ─── Build tools ─────────────────────────────────────────────────────
var tools = new AIFunction[]
{
    AIFunctionFactory.Create(SearchWebAsync, "SearchWeb"),
    AIFunctionFactory.Create(TakeNote, "TakeNote"),
    AIFunctionFactory.Create(GetNotes, "GetNotes"),
};

// ─── Build chat client with automatic function invocation ────────────
IChatClient client = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelName)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// ─── Interactive prompt ──────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 AI Research Agent           ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided.");
    return 1;
}

Console.WriteLine($"\n  Researching: \"{topic}\"\n");
Console.WriteLine("─────────────────────────────────────────");

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a thorough research agent. Use the available tools to research the
        user's topic by following these steps:

        1. Run 2-3 web searches with varied queries for broad coverage.
        2. Save every important finding with TakeNote.
        3. Call GetNotes to review everything you have gathered.
        4. Write a well-structured summary with headings, key facts, and insights.
        """),
    new(ChatRole.User, $"Research this topic and summarize your findings: {topic}"),
};

var options = new ChatOptions { Tools = [.. tools] };

await foreach (var update in client.GetStreamingResponseAsync(messages, options))
{
    Console.Write(update.Text);
}

Console.WriteLine();
Console.WriteLine("─────────────────────────────────────────");
Console.WriteLine($"  Research complete · {notes.Count} notes collected");
return 0;

// ─── Tool implementations ────────────────────────────────────────────

[Description("Search the web for information on a query. Returns up to 5 result snippets.")]
async Task<string> SearchWebAsync(
    [Description("The search query")] string query)
{
    WriteToolStatus("SearchWeb", query);

    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

    try
    {
        var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
        var html = await http.GetStringAsync(url);

        var results = new List<string>();
        foreach (Match m in Regex.Matches(html,
            @"<a class=""result__a""[^>]*>(?<title>.*?)</a>.*?"
          + @"<a class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
            RegexOptions.Singleline))
        {
            var title = StripHtml(m.Groups["title"].Value);
            var snippet = StripHtml(m.Groups["snippet"].Value);
            if (!string.IsNullOrWhiteSpace(snippet))
            {
                results.Add($"• {title}\n  {snippet}");
                if (results.Count >= 5) break;
            }
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : "No results found. Try rephrasing the query.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

[Description("Save a research note with a title and detailed content.")]
string TakeNote(
    [Description("Short title for the note")] string title,
    [Description("The finding or information to record")] string content)
{
    WriteToolStatus("TakeNote", title);
    notes.Add(new(title, content));
    return $"Saved note #{notes.Count}: \"{title}\"";
}

[Description("Retrieve all research notes collected so far.")]
string GetNotes()
{
    WriteToolStatus("GetNotes", $"{notes.Count} notes");

    if (notes.Count == 0)
        return "No notes taken yet.";

    var sb = new StringBuilder();
    for (var i = 0; i < notes.Count; i++)
        sb.AppendLine($"[{i + 1}] {notes[i].Title}\n    {notes[i].Content}\n");
    return sb.ToString();
}

// ─── Helpers ─────────────────────────────────────────────────────────

static string StripHtml(string input) =>
    WebUtility.HtmlDecode(Regex.Replace(input, "<.*?>", ""));

static void WriteToolStatus(string tool, string detail)
{
    Console.ForegroundColor = ConsoleColor.DarkCyan;
    Console.WriteLine($"\n  🔧 {tool}: {detail}");
    Console.ResetColor();
}

